const fail = (message) => [{
  json: {
    success: false,
    error: message,
  },
}];

const body = $input.first().json.body;

if (!body || typeof body !== 'object') {
  return fail('Invalid request body');
}

if (body.mode === 'regenerate_worksheet_answer') {
  if (!body.user_id || String(body.user_id).trim() === '') {
    return fail('Missing user_id');
  }

  if (!body.question || typeof body.question !== 'object') {
    return fail('Missing question');
  }

  return [{
    json: {
      success: true,
      mode: 'regenerate_worksheet_answer',
      regenerate_mode: body.regenerate_mode || 'worksheet_answer',
      user_id: String(body.user_id).trim(),
      metadata: body.metadata || {},
      question: body.question,
      current_answer: body.current_answer || {},
      answer_key_instruction: String(body.answer_key_instruction || '').substring(0, 1000),
    },
  }];
}

const required = ['subject', 'grade', 'topic', 'duration', 'objectives', 'language'];
const missing = required.filter(f => !body[f] || String(body[f]).trim() === '');

if (missing.length > 0) {
  return fail('Missing fields: ' + missing.join(', '));
}

if (!body.user_id || String(body.user_id).trim() === '') {
  return fail('Missing user_id');
}

const controls = body.question_controls || body.question_counts || {};

const clamp = (value, fallback, min, max) => {
  const n = Number(value ?? fallback);
  if (!Number.isFinite(n)) return fallback;
  return Math.max(min, Math.min(max, Math.round(n)));
};

const question_controls = {
  worksheet_mcq: clamp(controls.worksheet_mcq ?? body.worksheetMcqQuestions, 2, 0, 10),
  one_mark: clamp(controls.one_mark ?? body.oneMarkQuestions, 2, 0, 10),
  two_mark: clamp(controls.two_mark ?? body.twoMarkQuestions, 2, 0, 10),
  five_mark: clamp(controls.five_mark ?? body.fiveMarkQuestions, 1, 0, 10),
  mcq: clamp(controls.mcq ?? body.mcqQuestions, 10, 10, 10),
};

const guidance = body.grade_level_guidance || {};

const grade_level_guidance = {
  grade: guidance.grade ?? null,
  target_thinking_level: String(
    guidance.target_thinking_level ||
    'Use a general grade-appropriate mix of Remember, Understand, Apply, and Analyze questions.'
  ).substring(0, 500),
  recommended_question_types: String(
    guidance.recommended_question_types ||
    'Use clear MCQs, short answer questions, medium answer questions, and long answer questions suitable for the stated grade.'
  ).substring(0, 1200),
};

return [{
  json: {
    success: true,
    mode: body.mode || '',
    user_id: String(body.user_id).trim().substring(0, 100),
    subject: String(body.subject).trim().substring(0, 100),
    grade: String(body.grade).trim().substring(0, 50),
    topic: String(body.topic).trim().substring(0, 100),
    duration: String(body.duration).trim().substring(0, 50),
    objectives: String(body.objectives).trim().substring(0, 500),
    language: ['English', 'Hindi'].includes(body.language) ? body.language : 'English',
    question_controls,
    grade_level_guidance,
    worksheet_format_instruction: String(body.worksheet_format_instruction || '').substring(0, 3000),
    answer_key_instruction: String(body.answer_key_instruction || '').substring(0, 1000),
  },
}];

const d = $input.first().json;

const qc = d.question_controls || {
  worksheet_mcq: 2,
  one_mark: 2,
  two_mark: 2,
  five_mark: 1,
  mcq: 10,
};

qc.worksheet_mcq = Number(qc.worksheet_mcq ?? 2);
qc.one_mark = Number(qc.one_mark ?? 2);
qc.two_mark = Number(qc.two_mark ?? 2);
qc.five_mark = Number(qc.five_mark ?? 1);
qc.mcq = Number(qc.mcq ?? 10);

const gradeGuidance = d.grade_level_guidance || {
  grade: null,
  target_thinking_level:
    'Use a general grade-appropriate mix of Remember, Understand, Apply, and Analyze questions.',
  recommended_question_types:
    'Use clear MCQs, short answer questions, medium answer questions, and long answer questions suitable for the stated grade.',
};

const worksheetTotal =
  qc.worksheet_mcq * 1 +
  qc.one_mark * 1 +
  qc.two_mark * 2 +
  qc.five_mark * 5;

const quizTotal = qc.mcq * 1;

const makeQuestions = (count, startNumber, marks, difficulty) =>
  Array.from({ length: count }, (_, i) => ({
    q_number: startNumber + i,
    question: 'FILL',
    difficulty,
    marks,
  }));

const makeMcqs = (count, startNumber = 1) =>
  Array.from({ length: count }, (_, i) => ({
    q_number: startNumber + i,
    question: 'FILL',
    options: {
      A: 'FILL',
      B: 'FILL',
      C: 'FILL',
      D: 'FILL',
    },
    correct_option: ['A', 'B', 'C', 'D'][i % 4],
    marks: 1,
  }));

let worksheetQNumber = 1;

const worksheetMcqs = makeMcqs(qc.worksheet_mcq, worksheetQNumber);
worksheetQNumber += qc.worksheet_mcq;

const sectionB = makeQuestions(qc.one_mark, worksheetQNumber, 1, 'easy');
worksheetQNumber += qc.one_mark;

const sectionC = makeQuestions(qc.two_mark, worksheetQNumber, 2, 'medium');
worksheetQNumber += qc.two_mark;

const sectionD = makeQuestions(qc.five_mark, worksheetQNumber, 5, 'hard');

const quizMcqs = makeMcqs(qc.mcq, 1);

const worksheetAnswers = [
  ...worksheetMcqs.map(q => ({
    q_number: q.q_number,
    answer: q.correct_option,
    explanation: 'FILL',
  })),
  ...sectionB.map(q => ({
    q_number: q.q_number,
    answer: 'FILL',
    explanation: 'FILL',
  })),
  ...sectionC.map(q => ({
    q_number: q.q_number,
    answer: 'FILL with a complete 30-50 word model answer',
    explanation: 'Brief marking guidance',
  })),
  ...sectionD.map(q => ({
    q_number: q.q_number,
    answer: 'FILL with a complete 100-150 word model answer',
    explanation: 'Brief marking guidance',
  })),
];

const quizAnswers = quizMcqs.map(q => ({
  q_number: q.q_number,
  answer: q.correct_option,
  explanation: 'FILL',
}));

const expectedJson = {
  metadata: {
    subject: d.subject,
    grade: d.grade,
    topic: d.topic,
    duration: d.duration,
    language: d.language,
    objectives: d.objectives,
    generated_at: '',
    question_counts: qc,
    grade_level_guidance: gradeGuidance,
  },

  lesson_plan: {
    warm_up: {
      duration: '5 minutes',
      activity:
        'Write a detailed 3-5 sentence warm-up activity with teacher action and expected student response.',
      purpose:
        'Explain in 2-3 sentences how this warm-up activates prior knowledge and connects to the topic.',
    },
    concept_introduction: {
      duration: '10 minutes',
      content:
        'Write 2-3 detailed grade-appropriate paragraphs explaining the concept clearly with examples.',
      key_terms: ['term1', 'term2', 'term3', 'term4', 'term5'],
    },
    guided_activity: {
      duration: '15 minutes',
      description:
        'Write step-by-step classroom instructions including teacher actions, student task, expected output, and timing.',
      materials: ['item1', 'item2', 'item3'],
    },
    recap: {
      duration: '5 minutes',
      questions: ['q1', 'q2', 'q3', 'q4'],
    },
    homework: {
      description:
        'Write a clear homework task with expected answer length and submission expectation.',
    },
  },

  worksheet: {
    instructions: 'Answer the following questions to the best of your ability.',
    mcq: worksheetMcqs,
    sections: [
      {
        section_title: 'Section B - One Word / One Sentence Answer Questions',
        questions: sectionB,
      },
      {
        section_title: 'Section C - Short Answer Questions',
        questions: sectionC,
      },
      {
        section_title: 'Section D - Long Answer Questions',
        questions: sectionD,
      },
    ],
    total_marks: worksheetTotal,
  },

  quiz: {
    instructions: 'Choose the best answer for each question.',
    mcq: quizMcqs,
    short_answer: [],
    total_marks: quizTotal,
  },

  answer_key: {
    worksheet_answers: worksheetAnswers,
    quiz_answers: quizAnswers,
    grading_rubric: {
      total_marks: worksheetTotal,
      grade_bands: [
        {
          range: Math.ceil(worksheetTotal * 0.8) + '-' + worksheetTotal,
          grade: 'A',
          descriptor: 'Excellent',
        },
        {
          range:
            Math.ceil(worksheetTotal * 0.6) +
            '-' +
            (Math.ceil(worksheetTotal * 0.8) - 1),
          grade: 'B',
          descriptor: 'Good',
        },
        {
          range:
            Math.ceil(worksheetTotal * 0.4) +
            '-' +
            (Math.ceil(worksheetTotal * 0.6) - 1),
          grade: 'C',
          descriptor: 'Satisfactory',
        },
        {
          range: '0-' + (Math.ceil(worksheetTotal * 0.4) - 1),
          grade: 'D',
          descriptor: 'Needs Improvement',
        },
      ],
    },
  },
};

const prompt = [
  'You are an expert curriculum designer and experienced classroom teacher.',
  'Generate a complete, detailed, classroom-ready lesson kit.',
  'Return ONLY raw JSON. Do not use markdown, code fences, comments, or explanation.',
  '',

  'CRITICAL JSON RULES:',
'- Return valid JSON only.',
'- Every key must use double quotes.',
'- Every string must use double quotes.',
'- Do not use markdown.',
'- Do not use trailing commas.',
'- Do not stop until the full JSON object is complete.',
'- Before returning, mentally validate that every opened { and [ is properly closed.',
'- lesson_plan.warm_up, lesson_plan.concept_introduction, lesson_plan.guided_activity, lesson_plan.recap, and lesson_plan.homework must be sibling objects, not nested inside each other.',
'- worksheet.total_marks must be outside worksheet.sections, not inside the sections array.',
'',

    'Lesson details:',
  'Subject: ' + d.subject,
  'Grade: ' + d.grade,
  'Topic: ' + d.topic,
  'Duration: ' + d.duration,
  'Objectives: ' + d.objectives,
  'Language: ' + d.language,
  '',

  'FRONTEND WORKSHEET FORMAT INSTRUCTION:',
  d.worksheet_format_instruction || 'Use the worksheet counts and grade-level guidance exactly as provided.',
  '',

  'GRADE-LEVEL THINKING GUIDANCE:',
  '- Target thinking level: ' + gradeGuidance.target_thinking_level,
  '- Recommended question types: ' + gradeGuidance.recommended_question_types,
  '- Use this guidance mainly for worksheet questions, and lightly for quiz MCQs.',
  '- Do not show Bloom, DOK, or thinking-level labels in the student worksheet.',
  '- Keep the worksheet clean and teacher-friendly.',
  '',

  'LESSON PLAN DETAIL RULES:',
  '- The lesson_plan must be detailed enough that a teacher can directly teach from it.',
  '- warm_up.activity must be 3-5 sentences and include teacher action plus expected student response.',
  '- warm_up.purpose must be 2-3 sentences explaining why the warm-up connects to the topic.',
  '- concept_introduction.content must be 2-3 detailed paragraphs suitable for the grade level.',
  '- concept_introduction.content must include examples, definitions, and simple explanations.',
  '- concept_introduction.key_terms must include 5-8 important terms.',
  '- guided_activity.description must include step-by-step teacher instructions, student task, expected output, and timing.',
  '- guided_activity.materials must include all required classroom materials.',
  '- recap.questions must include 4-6 useful recap questions.',
  '- homework.description must include a clear task, expected answer length, and submission expectation.',
  '- Avoid short generic lines. Every lesson-plan section should be useful for a real teacher.',
  '',

  'WORKSHEET STRUCTURE RULES:',
  '- The worksheet must have exactly 4 sections.',
  '- Section A must be worksheet.mcq.',
  '- Section B must be inside worksheet.sections.',
  '- Section C must be inside worksheet.sections.',
  '- Section D must be inside worksheet.sections.',
  '- Worksheet MCQs must be newly generated for the worksheet.',
  '- Do not copy quiz MCQs into worksheet.mcq.',
  '- Quiz MCQs and worksheet MCQs must be different.',
  '',

  'STRICT WORKSHEET QUESTION COUNT RULES:',
  '- Generate exactly ' + qc.worksheet_mcq + ' worksheet MCQs in worksheet.mcq for Section A.',
  '- Generate exactly ' + qc.one_mark + ' one-mark questions in Section B.',
  '- Generate exactly ' + qc.two_mark + ' two-mark questions in Section C.',
  '- Generate exactly ' + qc.five_mark + ' five-mark questions in Section D.',
  '- Do not generate more or fewer worksheet questions than these counts.',
  '',

  'WORKSHEET MARKS RULES:',
  '- Section A MCQ marks must always be 1.',
  '- Section B question marks must always be 1.',
  '- Section C question marks must always be 2.',
  '- Section D question marks must always be 5.',
  '- worksheet.total_marks must equal ' + worksheetTotal + '.',
  '',

  'QUIZ RULES:',
  '- Generate exactly ' + qc.mcq + ' quiz MCQs in quiz.mcq.',
  '- Quiz MCQs must be separate from worksheet MCQs.',
  '- Each quiz MCQ must have 4 options: A, B, C, D.',
  '- Each quiz MCQ must have marks: 1.',
  '- quiz.short_answer must be an empty array.',
  '- quiz.total_marks must equal ' + quizTotal + '.',
  '',

  'ANSWER KEY RULES:',
  '- answer_key.worksheet_answers must contain exactly ' +
    worksheetAnswers.length +
    ' answers.',
  '- answer_key.worksheet_answers must include answers for worksheet.mcq and all worksheet.sections questions.',
  '- answer_key.quiz_answers must contain exactly ' +
    qc.mcq +
    ' answers.',
  '- answer_key.quiz_answers must include answers only for quiz.mcq questions.',
  '- Do not put quiz answers inside worksheet_answers.',
  '- Do not put worksheet answers inside quiz_answers.',
  '- Every answer should include a helpful explanation.',
  '- answer_key.grading_rubric.total_marks must equal worksheet.total_marks only.',
  '- Grading rubric must not include quiz marks.',
  '',

  'ANSWER LENGTH RULES:',
d.answer_key_instruction ||
  'For answer_key.worksheet_answers: Section C two-mark short-answer answers must be around 30-50 words each. Section D five-mark long-answer answers must be around 100-150 words each.',
'- One-mark answers should be concise.',
'- Two-mark / Section C answers should be around 30-50 words each.',
'- Five-mark / Section D answers should be around 100-150 words each.',
'- Put the complete model answer in the answer field. Use explanation only for brief marking guidance if needed.',
'',

  'Return this exact JSON structure with all fields filled.',
  'Preserve the same array lengths and marks values shown here:',
  JSON.stringify(expectedJson),
].join('\n');

return [
  {
    json: {
      expected_counts: {
        worksheet_mcq: qc.worksheet_mcq,
        one_mark: qc.one_mark,
        two_mark: qc.two_mark,
        five_mark: qc.five_mark,
        quiz_mcq: qc.mcq,
        worksheet_answers:
          qc.worksheet_mcq + qc.one_mark + qc.two_mark + qc.five_mark,
        quiz_answers: qc.mcq,
        worksheet_total_marks: worksheetTotal,
        quiz_total_marks: quizTotal,
      },
      requestBody: {
        model: 'google/gemini-2.0-flash-001',
        messages: [
          {
            role: 'user',
            content: prompt,
          },
        ],
        temperature: 0.2,
        max_tokens: 24000,
        response_format: { type: 'json_object' },
      },
    },
  },
];

const response = $input.first().json;
const rawText = response?.choices?.[0]?.message?.content;

if (!rawText) {
  return [{
    json: { success: false, error: "AI returned empty response" }
  }];
}

let cleaned = rawText.trim();
cleaned = cleaned.replace(/^```json\s*/i, '');
cleaned = cleaned.replace(/^```\s*/i, '');
cleaned = cleaned.replace(/\s*```$/i, '');
cleaned = cleaned.trim();

let lessonKit;

try {
  lessonKit = JSON.parse(cleaned);
} catch (e) {
  return [{
    json: {
      success: false,
      error: "Invalid JSON from AI: " + cleaned.substring(0, 200)
    }
  }];
}

if (lessonKit.success && lessonKit.data) {
  lessonKit = lessonKit.data;
}

const required = ['metadata', 'lesson_plan', 'worksheet', 'quiz', 'answer_key'];
const missing = required.filter(k => !lessonKit[k]);

if (missing.length > 0) {
  return [{
    json: {
      success: false,
      error: "Missing sections: " + missing.join(', ')
    }
  }];
}

lessonKit.worksheet.mcq = Array.isArray(lessonKit.worksheet.mcq)
  ? lessonKit.worksheet.mcq
  : [];

lessonKit.worksheet.sections = Array.isArray(lessonKit.worksheet.sections)
  ? lessonKit.worksheet.sections
  : [];

lessonKit.quiz.mcq = Array.isArray(lessonKit.quiz.mcq)
  ? lessonKit.quiz.mcq
  : [];

lessonKit.quiz.short_answer = [];

const expected = $('Build Prompt').first().json.expected_counts;

const fail = (message) => [{
  json: {
    success: false,
    error: message,
  },
}];

const sectionQuestions = (index) => {
  const section = lessonKit.worksheet.sections[index];
  return Array.isArray(section?.questions) ? section.questions : [];
};

if (lessonKit.worksheet.mcq.length !== expected.worksheet_mcq) {
  return fail(
    'AI generated incorrect worksheet MCQ count. Expected ' +
    expected.worksheet_mcq +
    ', got ' +
    lessonKit.worksheet.mcq.length
  );
}

if (sectionQuestions(0).length !== expected.one_mark) {
  return fail(
    'AI generated incorrect one-mark question count. Expected ' +
    expected.one_mark +
    ', got ' +
    sectionQuestions(0).length
  );
}

if (sectionQuestions(1).length !== expected.two_mark) {
  return fail(
    'AI generated incorrect two-mark question count. Expected ' +
    expected.two_mark +
    ', got ' +
    sectionQuestions(1).length
  );
}

if (sectionQuestions(2).length !== expected.five_mark) {
  return fail(
    'AI generated incorrect five-mark question count. Expected ' +
    expected.five_mark +
    ', got ' +
    sectionQuestions(2).length
  );
}

if (lessonKit.quiz.mcq.length !== expected.quiz_mcq) {
  return fail(
    'AI generated incorrect quiz MCQ count. Expected ' +
    expected.quiz_mcq +
    ', got ' +
    lessonKit.quiz.mcq.length
  );
}

if (lessonKit.answer_key.worksheet_answers.length !== expected.worksheet_answers) {
  return fail(
    'AI generated incorrect worksheet answer count. Expected ' +
    expected.worksheet_answers +
    ', got ' +
    lessonKit.answer_key.worksheet_answers.length
  );
}

if (lessonKit.answer_key.quiz_answers.length !== expected.quiz_answers) {
  return fail(
    'AI generated incorrect quiz answer count. Expected ' +
    expected.quiz_answers +
    ', got ' +
    lessonKit.answer_key.quiz_answers.length
  );
}

lessonKit.answer_key.worksheet_answers = Array.isArray(lessonKit.answer_key.worksheet_answers)
  ? lessonKit.answer_key.worksheet_answers
  : [];

lessonKit.answer_key.quiz_answers = Array.isArray(lessonKit.answer_key.quiz_answers)
  ? lessonKit.answer_key.quiz_answers
  : [];

const worksheetSectionMarks = lessonKit.worksheet.sections.reduce((sum, section) => {
  const questions = Array.isArray(section.questions) ? section.questions : [];
  return sum + questions.reduce((qSum, q) => qSum + Number(q.marks || 0), 0);
}, 0);

const worksheetMcqMarks = lessonKit.worksheet.mcq.reduce(
  (sum, q) => sum + Number(q.marks || 1),
  0
);

const worksheetTotal = worksheetMcqMarks + worksheetSectionMarks;

lessonKit.worksheet.total_marks = worksheetTotal;

if (!lessonKit.answer_key.grading_rubric) {
  lessonKit.answer_key.grading_rubric = {};
}

lessonKit.answer_key.grading_rubric.total_marks = worksheetTotal;
lessonKit.answer_key.grading_rubric.grade_bands = [
  {
    range: Math.ceil(worksheetTotal * 0.8) + '-' + worksheetTotal,
    grade: 'A',
    descriptor: 'Excellent',
  },
  {
    range:
      Math.ceil(worksheetTotal * 0.6) +
      '-' +
      (Math.ceil(worksheetTotal * 0.8) - 1),
    grade: 'B',
    descriptor: 'Good',
  },
  {
    range:
      Math.ceil(worksheetTotal * 0.4) +
      '-' +
      (Math.ceil(worksheetTotal * 0.6) - 1),
    grade: 'C',
    descriptor: 'Satisfactory',
  },
  {
    range: '0-' + (Math.ceil(worksheetTotal * 0.4) - 1),
    grade: 'D',
    descriptor: 'Needs Improvement',
  },
];

lessonKit.metadata.generated_at = new Date().toISOString();

return [{
  json: {
    success: true,
    data: lessonKit
  }
}];

const d = $input.first().json;

const question = d.question || {};
const currentAnswer = d.current_answer || {};

const prompt = [
  'You are an expert teacher.',
  'Regenerate ONLY the model answer for the given worksheet question.',
  'Do not change the question.',
  'Return ONLY valid JSON. No markdown. No explanation outside JSON.',
  '',
  'Lesson details:',
  'Subject: ' + d.metadata?.subject,
  'Grade: ' + d.metadata?.grade,
  'Topic: ' + d.metadata?.topic,
  'Language: ' + d.metadata?.language,
  '',
  'Question:',
  JSON.stringify(question),
  '',
  'Current answer:',
  JSON.stringify(currentAnswer),
  '',
  'Answer length rules:',
  d.answer_key_instruction || '',
  '',
  'Return exactly this JSON shape:',
  JSON.stringify({
    success: true,
    data: {
      answer: 'FILL',
      explanation: 'FILL',
    },
  }),
].join('\n');

return [{
  json: {
    requestBody: {
      model: 'google/gemini-2.0-flash-001',
      messages: [{ role: 'user', content: prompt }],
      temperature: 0.3,
      max_tokens: 1200,
      response_format: { type: 'json_object' },
    },
  },
}];

const res = $input.first().json;

const content =
  res.choices?.[0]?.message?.content ||
  res.body?.choices?.[0]?.message?.content ||
  '';

let parsed;

try {
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch (error) {
  return [{
    json: {
      success: false,
      error: 'AI returned invalid JSON for regenerated answer',
    },
  }];
}

const data = parsed.data || parsed;

if (!data.answer || String(data.answer).trim() === '') {
  return [{
    json: {
      success: false,
      error: 'AI did not return a regenerated answer',
    },
  }];
}

return [{
  json: {
    success: true,
    data: {
      answer: String(data.answer).trim(),
      explanation: String(data.explanation || '').trim(),
    },
  },
}];
